typedef struct {
  int input_n;
  int hidden_n;
  int output_n;

  float *input_units;
  float *hidden_units;
  float *output_units;

  float *hidden_delta;
  float *output_delta;

  float *target;

  float **input_weights;
  float **hidden_weights;

  float **input_prev_weights;
  float **hidden_prev_weights;
} BPNN;

static __device__ __forceinline__ float squash_dev(float x) {
  return 1.0f / (1.0f + expf(-x));
}

__global__ static void layerforward_kernel(float *l1, float *l2, float **conn, int n1, int n2) {
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= n2) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = squash_dev(sum);
  }
}

__global__ static void adjust_weights_kernel(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  int total = ndelta * (nly + 1);
  if (idx < total) {
    int j = idx / (nly + 1) + 1;
    int k = idx % (nly + 1);
    float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
    w[k][j] += new_dw;
    oldw[k][j] = new_dw;
  }
}

float drnd() {
