float *alloc_1d_dbl(int n) {
  float *newp = NULL;
  if (cudaMallocManaged((void **) &newp, (size_t)n * sizeof(float)) != cudaSuccess) {
    printf("ALLOC_1D_DBL: Couldn't allocate array of floats\n");
    return NULL;
  }
  return newp;
}

float **alloc_2d_dbl(int m, int n) {
  float **newp = NULL;
  if (cudaMallocManaged((void **) &newp, (size_t)m * sizeof(float *)) != cudaSuccess) {
    printf("ALLOC_2D_DBL: Couldn't allocate array of dbl ptrs\n");
    return NULL;
  }

  for (int i = 0; i < m; i++) {
    newp[i] = alloc_1d_dbl(n);
    if (newp[i] == NULL) {
      return NULL;
    }
  }

  return newp;
}

void bpnn_randomize_weights(float **w, int m, int n) {
  for (int i = 0; i <= m; i++) {
    for (int j = 0; j <= n; j++) {
      w[i][j] = (float) rand() / RAND_MAX;
    }
  }
}

void bpnn_randomize_row(float *w, int m) {
  for (int i = 0; i <= m; i++) {
    w[i] = 0.1f;
  }
}

void bpnn_zero_weights(float **w, int m, int n) {
  for (int i = 0; i <= m; i++) {
    for (int j = 0; j <= n; j++) {
      w[i][j] = 0.0f;
    }
  }
}

void bpnn_initialize(int seed) {
  printf("Random number generator seed: %d\n", seed);
  srand(seed);
}

BPNN *bpnn_internal_create(int n_in, int n_hidden, int n_out) {
  BPNN *newnet;

  newnet = (BPNN *) malloc(sizeof(BPNN));
  if (newnet == NULL) {
    printf("BPNN_CREATE: Couldn't allocate neural network\n");
    return NULL;
  }

  newnet->input_n = n_in;
  newnet->hidden_n = n_hidden;
  newnet->output_n = n_out;
  newnet->input_units = alloc_1d_dbl(n_in + 1);
  newnet->hidden_units = alloc_1d_dbl(n_hidden + 1);
  newnet->output_units = alloc_1d_dbl(n_out + 1);

  newnet->hidden_delta = alloc_1d_dbl(n_hidden + 1);
  newnet->output_delta = alloc_1d_dbl(n_out + 1);
  newnet->target = alloc_1d_dbl(n_out + 1);

  newnet->input_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);

  newnet->input_prev_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_prev_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);

  return newnet;
}

void bpnn_free(BPNN *net) {
  int n1, n2;

  n1 = net->input_n;
  n2 = net->hidden_n;

  cudaFree(net->input_units);
  cudaFree(net->hidden_units);
  cudaFree(net->output_units);

  cudaFree(net->hidden_delta);
  cudaFree(net->output_delta);
  cudaFree(net->target);

  for (int i = 0; i <= n1; i++) {
    cudaFree(net->input_weights[i]);
    cudaFree(net->input_prev_weights[i]);
  }
  cudaFree(net->input_weights);
  cudaFree(net->input_prev_weights);

  for (int i = 0; i <= n2; i++) {
    cudaFree(net->hidden_weights[i]);
    cudaFree(net->hidden_prev_weights[i]);
  }
  cudaFree(net->hidden_weights);
  cudaFree(net->hidden_prev_weights);

  free((char *) net);
}

BPNN *bpnn_create(int n_in, int n_hidden, int n_out) {
  BPNN *newnet;

  newnet = bpnn_internal_create(n_in, n_hidden, n_out);

#ifdef INITZERO
  bpnn_zero_weights(newnet->input_weights, n_in, n_hidden);
#else
  bpnn_randomize_weights(newnet->input_weights, n_in, n_hidden);
#endif
  bpnn_randomize_weights(newnet->hidden_weights, n_hidden, n_out);
  bpnn_zero_weights(newnet->input_prev_weights, n_in, n_hidden);
  bpnn_zero_weights(newnet->hidden_prev_weights, n_hidden, n_out);
  bpnn_randomize_row(newnet->target, n_out);
  return newnet;
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  l1[0] = 1.0f;
  int blocks = (n2 + THREADS - 1) / THREADS;
  layerforward_kernel<<<blocks, THREADS>>>(l1, l2, conn, n1, n2);
  cudaDeviceSynchronize();
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  float o, t, errsum;
  errsum = 0.0f;
  for (int j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  float h, sum, errsum;

  errsum = 0.0f;
  for (int j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0f;
    for (int k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  ly[0] = 1.0f;
  int total = ndelta * (nly + 1);
  int blocks = (total + THREADS - 1) / THREADS;
  adjust_weights_kernel<<<blocks, THREADS>>>(delta, ndelta, ly, nly, w, oldw);
  cudaDeviceSynchronize();
}

void bpnn_feedforward(BPNN *net) {
  int in, hid, out;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh) {
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

void bpnn_save(BPNN *net, char *filename) {
  int n1, n2, n3, i, j, memcnt;
  float dvalue, **w;
  char *mem;

  FILE *pFile;
  pFile = fopen(filename, "w+");

