  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

void load(BPNN *net) {
  float *units;
  int nr, nc, imgsize, i, k;

  nr = layer_size;
  nc = 0;

  imgsize = nr * nc;
  (void) imgsize;

  units = net->input_units;

  k = 1;
  for (i = 0; i < nr; i++) {
    units[k] = (float) rand() / RAND_MAX;
    k++;
  }
